            "type": "block",
            "position": {
              "x": 1440,
              "y": 140,
              "w": 420,
              "h": 170
            }
          },
          {
            "item": "viz_icon_kpi_uptime",
            "type": "block",
            "position": {
              "x": 1460,
              "y": 160,
              "w": 130,
              "h": 130
            }
          },
          {
            "item": "viz_value_kpi_uptime",
            "type": "block",
            "position": {
